function currentLang(){
  const l = (document.documentElement.lang || 'az').toLowerCase();
  if(l.startsWith('en')) return 'en';
  if(l.startsWith('ru')) return 'ru';
  if(l.startsWith('tr')) return 'tr';
  return 'az';
}
