// ---- Seans Modal Mühərriki ----
// Hər səhifə öz SESSIONS massivini və TOTAL_SESSIONS dəyərini təyin etməlidir
function renderSession(s){
  const t = UI[currentLang()];
  const total = (typeof TOTAL_SESSIONS !== 'undefined') ? TOTAL_SESSIONS : s.num;
  let html = `<span class="m-tag">${t.session} ${s.num} / ${total}</span><h3 class="m-title">${s.title}</h3>`;
  if(s.about){
    html += `<div class="m-block"><h5>${t.about}</h5><div class="m-goal">${s.about}</div></div>`;
  }
  html += `<div class="m-block"><h5>${t.goal}</h5><div class="m-goal">${s.goal}</div></div>`;
  if(s.specialists && s.specialists.length){
    html += `<div class="m-block"><h5>${t.specialists}</h5><div class="m-materials">${s.specialists.map(m=>`<span>${m}</span>`).join('')}</div></div>`;
  }
  if(s.materials && s.materials.length){
    html += `<div class="m-block"><h5>${t.materials}</h5><div class="m-materials">${s.materials.map(m=>`<span>${m}</span>`).join('')}</div></div>`;
  }
  html += `<div class="m-block"><h5>${t.flow}</h5>`;
  s.phases.forEach(ph=>{
    html += `<div class="m-phase"><div class="ph-name">${ph.name}</div>`;
    (ph.text||[]).forEach(x=>{ html += `<p>${x}</p>`; });
    if(ph.dialog && ph.dialog.length){
      html += `<div class="m-dialog">`;
      ph.dialog.forEach(d=>{
        const who = d[0]==='T' ? t.therapist : (d[0]==='K' ? t.client : (d[0]==='M' ? t.mother : (d[0]==='F' ? t.father : d[0])));
        const cls = d[0]==='T' ? 't' : 'k';
        html += `<div class="dl"><span class="dw ${cls}">${who}:</span><span class="dt">${d[1]}</span></div>`;
      });
      html += `</div>`;
    }
    html += `</div>`;
  });
  html += `</div>`;
  if(s.homework){
    html += `<div class="m-block"><h5>${t.homework}</h5><div class="m-homework">${s.homework}</div></div>`;
  }
  html += `<div class="m-nextprev">
    <div class="m-navbtn ${s.num<=1?'disabled':''}" onclick="openSession(${s.num-1})">${t.prev}</div>
    <div class="m-navbtn ${s.num>=total?'disabled':''}" onclick="openSession(${s.num+1})">${t.next}</div>
  </div>`;
  return html;
}

function openSession(n){
  if(typeof SESSIONS === 'undefined') return;
  const s = SESSIONS.find(x=>x.num===n);
  if(!s) return;
  document.getElementById('modalContent').innerHTML = renderSession(s);
  document.getElementById('modalOverlay').classList.add('active');
  document.body.classList.add('modal-open');
  const box = document.querySelector('.modal-box');
  if(box) box.scrollTop = 0;
}
function closeSession(){
  const ov = document.getElementById('modalOverlay');
  if(ov) ov.classList.remove('active');
  document.body.classList.remove('modal-open');
}
document.addEventListener('keydown', e=>{ if(e.key==='Escape') closeSession(); });

